const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const db = getFirestore(app);

export function watchAuth(cb) {
  return onAuthStateChanged(auth, cb);
}

// Erzeugt aus einem Benutzernamen eine interne Pseudo-E-Mail für Firebase Auth
// (Firebase Auth braucht technisch ein E-Mail-Format, die Nutzer sehen/tippen nur den Benutzernamen)
function usernameToEmail(username) {
  return username.trim().toLowerCase().replace(/[^a-z0-9_.-]/g, '') + "@mimhub.local";
}

// Verfügbare feste Ranking-Typen (Rookie kommt zusätzlich pro Jahr dazu, siehe unten)
export const LIST_TYPES = ['dynasty', 'redraft'];
// Jede Liste ist wiederum in drei Positions-Boards unterteilt
export const POSITIONS = ['DL', 'LB', 'DB'];
const emptyBoardObj = () => ({ inbox: [], t1: [], t2: [], t3: [], t4: [], t5: [], t6: [], t7: [] });
const emptyListDoc = () => ({
  boards: { DL: emptyBoardObj(), LB: emptyBoardObj(), DB: emptyBoardObj() },
  updatedAt: Date.now()
});

// Nur für den Admin gedacht (siehe admin.html) — legt einen festen Account
// samt Dynasty-, Redraft- und einer Rookie-Liste fürs laufende Jahr an, je
// mit drei Positions-Boards (DL/LB/DB). Weitere Rookie-Jahrgänge (rookie_2027,
// rookie_2028, …) werden automatisch beim ersten Speichern in rankings.html angelegt.
// Hinweis: Firebase meldet den Ersteller nach dem Anlegen automatisch als neuen
// User an; admin.html loggt danach automatisch wieder aus.
export async function createFixedUser(username, password, displayName) {
  const email = usernameToEmail(username);
  const cred = await createUserWithEmailAndPassword(auth, email, password);
  await updateProfile(cred.user, { displayName });
  await setDoc(doc(db, "rankings", cred.user.uid), { displayName, updatedAt: Date.now() });
  const currentYear = new Date().getFullYear();
  const listKeys = [...LIST_TYPES, `rookie_${currentYear}`];
  for (const listKey of listKeys) {
    await setDoc(doc(db, "rankings", cred.user.uid, "lists", listKey), emptyListDoc());
  }
  return cred.user;
}

export async function loginUser(username, password) {
  const email = usernameToEmail(username);
  const cred = await signInWithEmailAndPassword(auth, email, password);
  return cred.user;
}

export async function logoutUser() {
  await signOut(auth);
}

export async function loadBoard(userId, listType, positionTag) {
  const snap = await getDoc(doc(db, "rankings", userId, "lists", listType));
  if (snap.exists()) return snap.data()?.boards?.[positionTag] || null;
  return null;
}

// Speichert NUR das Board der übergebenen Position (DL/LB/DB) — die anderen
// beiden Positions-Boards im selben Listen-Dokument bleiben durch den
// nested merge unangetastet.
export async function saveBoard(userId, listType, positionTag, board) {
  await setDoc(doc(db, "rankings", userId, "lists", listType), {
    boards: { [positionTag]: board },
    updatedAt: Date.now()
  }, { merge: true });
}

// Live-Listener auf eine gesamte Liste (userId + Typ) — liefert alle drei
// Positions-Boards zusammen, damit man beim Wechseln des Positions-Tabs
// nicht neu abonnieren muss. Gibt eine unsubscribe-Funktion zurück.
export function watchBoard(userId, listType, cb) {
  return onSnapshot(doc(db, "rankings", userId, "lists", listType), snap => {
    cb(snap.exists() ? snap.data() : null);
  });
}

export async function listAllRankings() {
  const snap = await getDocs(collection(db, "rankings"));
  const out = [];
  snap.forEach(d => out.push({ id: d.id, ...d.data() }));
  return out;
}

// ── AVATARE (gemeinsam genutzt von rankings.html & player.html) ──────────
// Feste Logo-Zuordnung pro Nutzer — als Base64 direkt eingebettet (kein externer
// Dateipfad nötig, dadurch keine 404/Groß-Kleinschreibungs-Probleme mehr möglich).
// Nutzer ohne Eintrag hier bekommen automatisch einen Initialen-Avatar als Fallback.
export const AVATAR_MAP = {
  'tarik': 'data:image/png;base64,',
  'ralf': 'data:image/png;base64,',
  's7even': 'data:image/png;base64,',
  'tobi': 'data:image/png;base64,',
  'florian': 'data:image/png;base64,'
};
export function avatarFor(displayName){
  const norm = (displayName||'').toLowerCase().replace(/[^a-z0-9]/g,'');
  // Bekannte Schreibvarianten auf den jeweiligen AVATAR_MAP-Schlüssel abbilden
  const ALIASES = {
    'tarik': 'tarik',
    'ralf': 'ralf',
    's7even': 's7even', 'seven': 's7even', 's7': 's7even', '7even': 's7even', 'steven': 's7even',
    'tobi': 'tobi', 'tobias': 'tobi',
    'florian': 'florian', 'flo': 'florian'
  };
  if(ALIASES[norm]) return AVATAR_MAP[ALIASES[norm]];
  // Fallback: Teilstring-Abgleich, falls der Anzeigename leicht abweicht (z.B. Leerzeichen/Zusatz)
  for(const [alias, key] of Object.entries(ALIASES)){
    if(norm.includes(alias) || alias.includes(norm)) return AVATAR_MAP[key];
  }
  return null;
}

// Liest ein komplettes Listen-Dokument einmalig (kein Live-Listener) — für
// player.html, das nur einmal beim Laden der Seite nachschauen muss, wo ein
// Spieler in den Rankings der 4 Nutzer steht.
export async function loadListDoc(userId, listType) {
  const snap = await getDoc(doc(db, "rankings", userId, "lists", listType));
  return snap.exists() ? snap.data() : null;
}

// ── COLLEGE SCOUTING ─────────────────────────────────────────────────────
// Ein Firestore-Dokument pro Jahr+Position (z.B. "2026_DL"), darin eine Map
// aller Spieler dieser Liste mit Stern-Status (für alle sichtbar/umschaltbar)
// und watchedBy (pro Nutzer-UID sein eigener "geschaut"-Haken).
function scoutingDocId(year, position){ return `${year}_${position}`; }

export async function loadScoutingDoc(year, position){
  const snap = await getDoc(doc(db, "scouting_status", scoutingDocId(year, position)));
  return snap.exists() ? snap.data() : { players: {} };
}

export function watchScoutingDoc(year, position, cb){
  return onSnapshot(doc(db, "scouting_status", scoutingDocId(year, position)), snap => {
    cb(snap.exists() ? snap.data() : { players: {} });
  });
}

export async function toggleScoutingStar(year, position, playerSlug, newVal){
  await setDoc(doc(db, "scouting_status", scoutingDocId(year, position)), {
    players: { [playerSlug]: { starred: newVal } }
  }, { merge: true });
}

export async function toggleScoutingWatched(year, position, playerSlug, uid, newVal){
  await setDoc(doc(db, "scouting_status", scoutingDocId(year, position)), {
    players: { [playerSlug]: { watchedBy: { [uid]: newVal } } }
  }, { merge: true });
}
